frappe.ui.form.on('Sales Invoice', {

    price_list(frm){

        let items = frm.doc.items.map(d => d.item);

        frappe.call({
            method: "get_items_prices",
            doc: frm.doc,
            args: {
                items: items,
                price_list: frm.doc.price_list
            },
            callback: function(r) {

                if (r.message) {

                    let prices = r.message;

                    frm.doc.items.forEach(row => {

                        let price = prices[row.item];

                        if (price !== undefined) {
                            frappe.model.set_value(
                                row.doctype,
                                row.name,
                                "rate",
                                price
                            );
                        }
                    });

                    frm.refresh_field("items");
                }
            }
        });
    },
    
    
    
});





frappe.ui.form.on('Sales Invoice Item', {
    
    items_add(frm, cdt, cdn){
        //task 1 ==> recalculate the total qty
        let total_qty = 0;
        frm.doc.items.forEach(item=>{ total_qty += (item.qty || 0)})
        frm.set_value("total_qty",total_qty)
    },
    items_remove(frm, cdt, cdn){
        //task 1 ==> recalculate the total qty
        let total_qty = 0;
        frm.doc.items.forEach(item=>{ total_qty += (item.qty || 0)})
        frm.set_value("total_qty",total_qty)
    },
    item(frm, cdt, cdn) {

        let row = locals[cdt][cdn];

        if (!row.item || !frm.doc.price_list) return;

        frappe.call({
            method: "get_items_prices",
            doc: frm.doc,
            args: {
                items: [row.item],
                price_list: frm.doc.price_list
            },
            callback: function(r) {

                if (r.message) {

                    let price = r.message[row.item];

                    if (price !== undefined) {
                        frappe.model.set_value(
                            cdt,
                            cdn,
                            "rate",
                            price
                        );
                    }
                }
            }
        });
    },
    qty(frm , cdt , cdn){
        // task 1 ==> recalculate the amount
        let row = locals[cdt][cdn]
        let amount = row.qty * row.rate
        frappe.model.set_value(cdt,cdn,"amount",amount)
        
        //task 2 ==> recalculate the total qty
        let total_qty = 0;
        frm.doc.items.forEach(item=>{ total_qty += (item.qty || 0)})
        frm.set_value("total_qty",total_qty)
    },
    rate(frm , cdt , cdn){
        
        let row = locals[cdt][cdn]
        let amount = row.qty * row.rate
        frappe.model.set_value(cdt,cdn,"amount",amount)
    }
    
});
